INSERT INTO questions (category, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, explanation, tags) VALUES
('DATA_STRUCTURES', 'Easy', 'What is the time complexity of accessing an element in an array by its index?', 'O(1)', 'O(n)', 'O(log n)', 'O(n log n)', 'A', 'Arrays provide constant-time O(1) access because elements are stored in contiguous memory locations and can be directly accessed using their index offset.', 'arrays,time-complexity'),
('DATA_STRUCTURES', 'Easy', 'Which data structure follows the LIFO (Last In, First Out) principle?', 'Queue', 'Stack', 'Linked List', 'Array', 'B', 'A Stack follows LIFO — the last element pushed onto the stack is the first one to be popped off. Think of a stack of plates.', 'stack,basics'),
('DATA_STRUCTURES', 'Easy', 'Which data structure follows the FIFO (First In, First Out) principle?', 'Stack', 'Tree', 'Queue', 'Graph', 'C', 'A Queue follows FIFO — the first element enqueued is the first to be dequeued, just like a real-life queue/line.', 'queue,basics'),
('DATA_STRUCTURES', 'Easy', 'What is the worst-case time complexity of searching for an element in an unsorted array?', 'O(1)', 'O(log n)', 'O(n)', 'O(n²)', 'C', 'In the worst case, you may need to check every element in the array (linear search), resulting in O(n) time complexity.', 'arrays,searching'),
('DATA_STRUCTURES', 'Medium', 'In a singly linked list, what is the time complexity of inserting a node at the beginning?', 'O(n)', 'O(1)', 'O(log n)', 'O(n²)', 'B', 'Inserting at the beginning of a linked list is O(1) because you only need to update the head pointer and the new node''s next reference.', 'linked-list,insertion'),
('DATA_STRUCTURES', 'Medium', 'What is the maximum number of nodes at level ''k'' in a binary tree?', '2k', '2^k', 'k²', '2^(k+1)', 'B', 'At level k (root at level 0), a binary tree can have at most 2^k nodes. Level 0 has 1 node, level 1 has 2, level 2 has 4, and so on.', 'binary-tree,properties'),
('DATA_STRUCTURES', 'Medium', 'Which of the following is NOT a self-balancing binary search tree?', 'AVL Tree', 'Red-Black Tree', 'B-Tree', 'Binary Search Tree', 'D', 'A plain Binary Search Tree (BST) does not guarantee balance. AVL Trees, Red-Black Trees, and B-Trees all have mechanisms to maintain balance during insertions and deletions.', 'bst,balanced-trees'),
('DATA_STRUCTURES', 'Medium', 'What is the average time complexity of search, insert, and delete operations in a hash table?', 'O(n)', 'O(log n)', 'O(1)', 'O(n log n)', 'C', 'Hash tables provide average O(1) time for search, insert, and delete by using a hash function to compute the index. However, worst case can be O(n) due to collisions.', 'hash-table,time-complexity'),
('DATA_STRUCTURES', 'Hard', 'What is the time complexity of building a heap from an unsorted array using the bottom-up approach?', 'O(n log n)', 'O(n²)', 'O(n)', 'O(log n)', 'C', 'Building a heap bottom-up (heapify) is O(n), not O(n log n). This is because the majority of nodes are at the lower levels and require fewer swaps. The mathematical proof uses the sum of a geometric series.', 'heap,time-complexity'),
('DATA_STRUCTURES', 'Hard', 'In a graph with V vertices and E edges, what is the space complexity of an adjacency matrix representation?', 'O(V + E)', 'O(V²)', 'O(E²)', 'O(V × E)', 'B', 'An adjacency matrix uses a V×V 2D array to represent edges, hence O(V²) space regardless of the number of edges. An adjacency list uses O(V + E).', 'graph,space-complexity'),
('DATA_STRUCTURES', 'Hard', 'Which data structure is most efficient for implementing a priority queue?', 'Sorted Array', 'Unsorted Linked List', 'Binary Heap', 'Stack', 'C', 'A Binary Heap provides O(log n) insert and O(log n) extract-min/max, making it the most efficient general-purpose priority queue implementation. Sorted arrays have O(n) insertion.', 'heap,priority-queue'),
('DATA_STRUCTURES', 'Hard', 'What is a Trie data structure primarily used for?', 'Sorting integers', 'Efficient string searching and prefix matching', 'Graph traversal', 'Matrix operations', 'B', 'A Trie (prefix tree) stores strings character-by-character in a tree structure. It enables O(m) search, insert, and prefix matching where m is the string length, making it ideal for autocomplete and spell-checkers.', 'trie,strings'),
('DATA_STRUCTURES', 'Medium', 'What traversal of a Binary Search Tree gives elements in sorted order?', 'Preorder', 'Postorder', 'Inorder', 'Level-order', 'C', 'Inorder traversal (Left, Root, Right) of a BST visits nodes in ascending order because all left subtree values are smaller and all right subtree values are larger than the root.', 'bst,traversal'),
('DATA_STRUCTURES', 'Easy', 'Which operation is NOT typically supported by a basic array?', 'Access by index', 'Dynamic resizing', 'Sequential traversal', 'Update by index', 'B', 'Basic arrays have a fixed size once allocated. Dynamic resizing requires a dynamic array (like ArrayList in Java or vector in C++), which internally creates a new larger array and copies elements.', 'arrays,basics'),
('DATA_STRUCTURES', 'Medium', 'What is the time complexity of deleting an element from the middle of a doubly linked list, given a pointer to that node?', 'O(n)', 'O(1)', 'O(log n)', 'O(n²)', 'B', 'With a direct pointer to the node, deletion in a doubly linked list is O(1) because you can update the previous and next pointers directly without traversal.', 'linked-list,deletion'),
('DATA_STRUCTURES', 'Hard', 'Identify the correct statement: In a graph with V vertices and E edges, what is the space complexity of an adjacency matrix representation? (Review)', 'O(V + E)', 'O(E²)', 'O(V × E)', 'O(V²)', 'D', 'An adjacency matrix uses a V×V 2D array to represent edges, hence O(V²) space regardless of the number of edges. An adjacency list uses O(V + E).', 'graph,space-complexity'),
('DATA_STRUCTURES', 'Easy', 'Which of the following is true? Which data structure follows the FIFO (First In, First Out) principle? (Variant)', 'Graph', 'Queue', 'Stack', 'Tree', 'B', 'A Queue follows FIFO — the first element enqueued is the first to be dequeued, just like a real-life queue/line.', 'queue,basics'),
('DATA_STRUCTURES', 'Medium', 'Identify the correct statement: What is the maximum number of nodes at level ''k'' in a binary tree? (Concept Check)', '2^k', '2k', 'k²', '2^(k+1)', 'A', 'At level k (root at level 0), a binary tree can have at most 2^k nodes. Level 0 has 1 node, level 1 has 2, level 2 has 4, and so on.', 'binary-tree,properties'),
('DATA_STRUCTURES', 'Medium', 'Technical check: What is the average time complexity of search, insert, and delete operations in a hash table? (Concept Check)', 'O(n log n)', 'O(log n)', 'O(n)', 'O(1)', 'D', 'Hash tables provide average O(1) time for search, insert, and delete by using a hash function to compute the index. However, worst case can be O(n) due to collisions.', 'hash-table,time-complexity'),
('DATA_STRUCTURES', 'Medium', 'Consider this: What is the average time complexity of search, insert, and delete operations in a hash table? (Review)', 'O(n log n)', 'O(1)', 'O(log n)', 'O(n)', 'B', 'Hash tables provide average O(1) time for search, insert, and delete by using a hash function to compute the index. However, worst case can be O(n) due to collisions.', 'hash-table,time-complexity'),
